import{Pagination}from"./utils.min.js";class PostUpload{constructor(){this.uploaderSlides=new Pagination(document.getElementsByClassName("uploader-panel")),document.getElementById("right-button").onclick=()=>{this.switchSlide(this.uploaderSlides.next)},document.getElementById("left-button").onclick=()=>{this.switchSlide(this.uploaderSlides.prev)},document.getElementById("upload-button").onclick=()=>{this.invokeForm()},document.getElementById("left-button-image").onclick=()=>{this.imagePages.hasPrev&&this.changeImage(this.imagePages.prev)},document.getElementById("right-button-image").onclick=()=>{this.imagePages.hasNext&&this.changeImage(this.imagePages.next)};let e=document.getElementById("file-upload");e.onchange=()=>{this.displayImages(e)}}displayImages(e){if(e.files&&e.files[0]){let t=[],i=[];for(let t of e.files){let e=new Promise(e=>{let i=new FileReader;i.readAsDataURL(t),i.onload=()=>e(i.result)});i.push(e)}Promise.all(i).then(e=>{for(let i of e){let e=document.createElement("img");e.className="preview-image",e.src=i,t.push(e)}this.imagePages=new Pagination(t),this.changeImage(this.imagePages.current)})}}changeImage(e){document.getElementById("preview-image").replaceChildren(e),document.getElementById("image-count").innerText=this.imagePages.currentPage+1}switchSlide(e){this.hideOtherSlides(e.dataset.slideName),this.updateSlideControls()}hideOtherSlides(e){for(let t of document.getElementsByClassName("uploader-panel"))t.dataset.slideName!=e?t.style.display="none":t.style.display="flex"}updateSlideControls(){let e=document.getElementById("right-button"),t=document.getElementById("left-button"),i=document.getElementById("upload-button");document.getElementById("uploader-title-text").innerText=this.uploaderSlides.current.dataset.slideTitle,this.uploaderSlides.hasNext&&this.uploaderSlides.hasPrev?(t.style.visibility="visible",e.style.visibility="visible",e.style.display="block",i.style.display="none"):!this.uploaderSlides.hasNext&&this.uploaderSlides.hasPrev?(t.style.visibility="visible",e.style.visibility="hidden",e.style.display="none",i.style.display="block"):this.uploaderSlides.hasNext&&!this.uploaderSlides.hasPrev&&(t.style.visibility="hidden",e.style.visibility="visible",e.style.display="block",i.style.display="none")}invokeForm(){let e=document.getElementById("uploader-form");0===document.getElementById("file-upload").files.length?alert("Please select some files!"):e.submit()}}export{PostUpload};